module binary_to_gray (
    input [3:0] gray_code,
    output [3:0] gray
);

    // Binary to Gray code conversion
    assign gray[3] = gray_code[3];
    assign gray[2] = gray_code[3] ^ gray_code[2];
    assign gray[1] = gray_code[2] ^ gray_code[1];
    assign gray[0] = gray_code[1] ^ gray_code[0];

endmodule
